#include <stdio.h>
int main() {
    int T, N, K, A[50], i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int nim_sum = 0;
        for (i = 0; i < N; i++) {
            int x = A[i];
            while (x > K) {
                x -= K;
            }
            nim_sum ^= x;
        }
        if (nim_sum == 0) {
            printf("Zeta\n");
        } else {
            printf("Nancy\n");
        }
    }
    return 0;
}

