import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int nim_sum = 0;
            for (int i = 0; i < N; i++) {
                int x = A[i];
                while (x > K) {
                    x -= K;
                }
                nim_sum ^= x;
            }
            if (nim_sum == 0) {
                System.out.println("Zeta");
            } else {
                System.out.println("Nancy");
            }
        }
    }
}

